// // (1) load: Loads counter with data[15:0] instead of counting. Asynchronous active low.
// (2) ena: Asynchronous. Disables counting if high.
// (3) up_down: If low, the counter counts up; if high, it counts down.
module top_module(
	input clk,
	input load,
	input ena,
	input up_down,
	input [15:0] data,
	output reg [15:0] q);always @(posedge clk) begin
		if (load)
			q <= data;
		else if (ena) begin
			if (up_down)
				q <= q + 1;
			else
				q <= q - 1;
		end
	end
endmodule

